statements:
    - context : >
        additional_user_data := {
            "digilockerTimestamp": string(now),
            "digilockerId": context.digi_id,
            "digilockerStatus": jsonToString({
                "phone_validation": 
                {
                    "match_status" : (has(context.phone_validation) && has(context.phone_validation.match_status)) ? context.phone_validation.match_status : ""
                },
                "email_validation": 
                {
                    "match_status" : (has(context.email_validation) && has(context.email_validation.match_status)) ? context.email_validation.match_status : ""
                },
                "name_validation": 
                {
                    "match_status" : (has(context.name_validation) && has(context.name_validation.match_status)) ? context.name_validation.match_status : ""
                },
                "dob_validation": 
                {
                    "match_status" : (has(context.dob_validation) && has(context.dob_validation.match_status)) ? context.dob_validation.match_status : ""
                }
            })
        }
    - context : userData :=  (context.cacheData.userData.putAll(context.additional_user_data))

    - return : > 
        {
            "userData" : context.userData
        }

